namespace NotificationsApp.Services;

public record NotificationItem(int Id, string Message, DateTime Timestamp);

public interface INotificationService
{
    Task<List<NotificationItem>> GetNotificationsAsync();
    Task<List<NotificationItem>> GetNotificationsSinceAsync(DateTime since);
}

public class NotificationService : INotificationService
{
    private static int _nextId = 4;
    private static readonly List<NotificationItem> _notifications = new()
    {
        new(1, "Welcome to the app!", new DateTime(2026, 5, 24, 10, 0, 0, DateTimeKind.Utc)),
        new(2, "Your profile was updated.", new DateTime(2026, 5, 24, 10, 15, 0, DateTimeKind.Utc)),
        new(3, "New feature: dark mode is available.", new DateTime(2026, 5, 24, 10, 30, 0, DateTimeKind.Utc)),
    };

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        return Task.FromResult(_notifications.ToList());
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(DateTime since)
    {
        // Simulate a new notification arriving ~every 10 seconds
        if (Random.Shared.Next(0, 2) == 0)
        {
            var id = Interlocked.Increment(ref _nextId);
            _notifications.Add(new NotificationItem(
                id,
                $"New event #{id} occurred.",
                DateTime.UtcNow));
        }

        var newer = _notifications.Where(n => n.Timestamp > since).ToList();
        return Task.FromResult(newer);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject INotificationService NotificationService
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@(notifications?.Count ?? 0)</span></h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Message</strong>
                <small class="text-muted ms-2">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not restored from prerender state
        notifications ??= await NotificationService.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is never called during prerender,
            // so this only fires once the page is truly interactive.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var since = notifications?.MaxBy(n => n.Timestamp)?.Timestamp ?? DateTime.MinValue;
            var newer = await NotificationService.GetNotificationsSinceAsync(since);

            if (newer.Count > 0)
            {
                notifications ??= new();
                notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

